from collections import deque

class Solution:
    def getAncestors(self, n, edges):
        adj = [[] for _ in range(n)]
        indeg = [0] * n
        for u, v in edges:
            adj[u].append(v)
            indeg[v] += 1
        q = deque(i for i in range(n) if indeg[i] == 0)
        remaining = indeg[:]
        order = []
        while q:
            u = q.popleft()
            order.append(u)
            for v in adj[u]:
                remaining[v] -= 1
                if remaining[v] == 0:
                    q.append(v)
        anc = [set() for _ in range(n)]
        for u in order:
            for v in adj[u]:
                anc[v].add(u)
                anc[v] |= anc[u]
        return [sorted(s) for s in anc]

