class Solution:
    def getAncestors(self, n, edges):
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
        ancestors = [set() for _ in range(n)]
        for start in range(n):
            visited = set()
            stack = list(adj[start])
            while stack:
                node = stack.pop()
                if node in visited:
                    continue
                visited.add(node)
                ancestors[node].add(start)
                stack.extend(adj[node])
        return [sorted(s) for s in ancestors]

